import Default from "~/assets/icons/folder/NinjaDefault";
import InlineStack from "~/components/inlineStack";
import { Theme } from "~/types/settings/settings";
import BlockStack from "~/components/blockStack";
import { useMemo } from "@wordpress/element";
import Button from "~/components/button";
import Input from "~/components/input";
import { __ } from "@wordpress/i18n";
import clsx from "clsx";
/* <fs_premium_only> */
import Awesome from "~/assets/icons/folder/Awesome";
import Bold from "~/assets/icons/folder/Bold";
import Icon from "~/components/icon";
/* </fs_premium_only> */

const CreateFolder = ({
    theme = "default",
    nested,
    inputRef,
    folderName = "New folder",
    setFolderName,
    onCreate,
    onCancel,
    loading = false,
}: {
    theme?: Theme;
    nested?: boolean;
    inputRef?: React.RefObject<HTMLInputElement>;
    folderName?: string;
    setFolderName?: (name: string) => void;
    onCreate?: () => void;
    onCancel?: () => void;
    loading?: boolean;
}) => {
    const iconElement = useMemo(() => {
        if (theme === "default") return <Default active={false} />;

        /* <fs_premium_only> */
        return (
            <InlineStack gap={theme === "awesome" ? 9 : 10} wrap={false}>
                <BlockStack
                    align="center"
                    inlineAlign="center"
                    className="pnpnm-folder__arrow"
                >
                    <Icon
                        name={
                            theme === "plugininja"
                                ? "arrow_drop_down"
                                : "keyboard_arrow_down"
                        }
                        fontSize={theme === "plugininja" ? "xl" : "lg"}
                    />
                </BlockStack>

                {theme === "bold" ? (
                    <Bold />
                ) : theme === "awesome" ? (
                    <Awesome />
                ) : (
                    <Default active={false} />
                )}
            </InlineStack>
        );
        /* </fs_premium_only> */
    }, [theme]);

    return (
        <BlockStack
            marginTop={5}
            gap={5}
            style={{
                paddingLeft: nested ? 10 : 0,
            }}
            className="pnpnm-folder-create"
        >
            <Input
                prefix={iconElement}
                size="extrasmall"
                placeholder={__("Folder Name", "ninja-media")}
                value={folderName}
                ref={inputRef}
                className={clsx(
                    theme === "default" && "pnpnm-folder-create--default",
                    /* <fs_premium_only> */
                    theme === "awesome" && "pnpnm-folder-create--awesome",
                    /* </fs_premium_only> */
                )}
                onChange={(value) => setFolderName?.(String(value))}
                onKeyDown={(e) => {
                    if (e.key === "Enter") {
                        onCreate?.();
                    }
                }}
            />

            <InlineStack gap={5} wrap={false}>
                <Button
                    variant="secondary"
                    size="supersmall"
                    rounded="xs"
                    onClick={onCancel}
                >
                    {__("Cancel", "ninja-media")}
                </Button>

                <Button
                    variant="primary"
                    size="supersmall"
                    rounded="xs"
                    startIcon="create_new_folder"
                    iconSize="sm"
                    onClick={onCreate}
                    loading={loading}
                >
                    {__("Create", "ninja-media")}
                </Button>
            </InlineStack>
        </BlockStack>
    );
};

export default CreateFolder;
