import { ServerResponse } from "~/types/response";
import { Folder } from "~/types/folder";
import { baseApi } from "./base";
import {
    AssignFileResponse,
    CreateFolderResponse,
    DeleteFileResponse,
    GetBreadcrumbsResponse,
    GetFolderResponse,
    GetFoldersResponse,
    RestoreFileResponse,
    UpdateFolderResponse,
    /* <fs_premium_only> */
    DownloadFolderResponse,
    TrashFileResponse,
    ReplaceMediaResponse,
    /* </fs_premium_only> */
} from "~/types/media/response";

export const media = baseApi.injectEndpoints({
    endpoints: (builder) => ({
        getFolders: builder.query<
            ServerResponse<GetFoldersResponse>,
            {
                orderBy?: "name" | "size" | "createdAt" | "updatedAt";
                order?: "ASC" | "DESC";
                search?: string;
            }
        >({
            query: ({ orderBy, order, search }) => {
                const params: Record<string, string> = {};

                if (orderBy) {
                    params.orderBy = orderBy;
                }
                if (order) {
                    params.order = order;
                }
                if (search) {
                    params.search = search;
                }

                return {
                    url: `media-library`,
                    method: "GET",
                    params,
                };
            },

            providesTags: ["Folders"],
        }),

        getFolder: builder.query<
            ServerResponse<GetFolderResponse>,
            { id: string | number }
        >({
            query: ({ id }) => {
                return {
                    url: `media-library/${id}`,
                    method: "GET",
                };
            },
        }),

        getBreadcrumbs: builder.query<
            ServerResponse<GetBreadcrumbsResponse>,
            { id: string | number }
        >({
            query: ({ id }) => {
                return {
                    url: `media-library/breadcrumbs`,
                    method: "GET",
                    params: {
                        id,
                    },
                };
            },
        }),

        createFolder: builder.mutation<
            ServerResponse<CreateFolderResponse>,
            { name: string; parentId?: string | number | null }
        >({
            query: ({ name, parentId }) => {
                return {
                    url: `media-library/folder`,
                    method: "POST",
                    body: {
                        name,
                        parentId,
                    },
                };
            },

            async onQueryStarted(
                { parentId },
                { dispatch, queryFulfilled, getState },
            ) {
                try {
                    const { data: result } = await queryFulfilled;
                    const newFolder = result?.data;

                    if (!newFolder || parentId) return;

                    const state = getState() as any;
                    const { folderSorting, order, search } = state.media;
                    const isForceSorting =
                        state.settings?.data?.general?.folder?.forceSorting ??
                        false;

                    if (isForceSorting) {
                        dispatch(media.util.invalidateTags(["Folders"]));
                        dispatch(
                            media.endpoints.getFolders.initiate(
                                {
                                    orderBy: folderSorting?.orderBy,
                                    order: order,
                                },
                                { forceRefetch: true },
                            ),
                        );
                    } else {
                        dispatch(
                            media.util.updateQueryData(
                                "getFolders",
                                {
                                    orderBy: folderSorting?.orderBy,
                                    order: order,
                                    search: search,
                                },
                                (draft) => {
                                    if (draft?.data?.folders) {
                                        draft.data.folders.unshift(newFolder);
                                        draft.data.totalFolders =
                                            (draft.data.totalFolders ?? 0) + 1;
                                    }
                                },
                            ),
                        );
                    }
                } catch {}
            },
        }),

        updateFolder: builder.mutation<
            ServerResponse<UpdateFolderResponse>,
            {
                id: string | number;
                name?: string;
                color?: string | null;
            }
        >({
            query: ({ id, name, color }) => {
                return {
                    url: `media-library/folder`,
                    method: "PUT",
                    body: {
                        id,
                        name,
                        color,
                    },
                };
            },
        }),

        copyFolder: builder.mutation<
            ServerResponse<{ folders: Folder[] }>,
            { parentId: string | number; id: string | number }
        >({
            query: ({ parentId, id }) => {
                return {
                    url: `media-library/folder/copy`,
                    method: "POST",
                    body: {
                        parentId,
                        ids: [id],
                    },
                };
            },
        }),

        moveFolder: builder.mutation<
            ServerResponse<null>,
            { id: string | number; ids: (string | number)[] }
        >({
            query: ({ id, ids }) => {
                return {
                    url: `media-library/folder/move`,
                    method: "POST",
                    body: {
                        parentId: id,
                        ids,
                    },
                };
            },
        }),

        deleteFolder: builder.mutation<
            ServerResponse<{ allFiles: number; uncategorized: number }>,
            { ids: (string | number)[]; isMediaDelete?: boolean }
        >({
            query: ({ ids, isMediaDelete }) => {
                return {
                    url: `media-library/folder`,
                    method: "DELETE",
                    body: {
                        ids,
                        isMediaDelete,
                    },
                };
            },
        }),

        assignFile: builder.mutation<
            ServerResponse<AssignFileResponse>,
            { id: string | number; attachments: (string | number)[] }
        >({
            query: ({ id, attachments }) => {
                return {
                    url: `media-library/folder/${id}/assign`,
                    method: "POST",
                    body: {
                        attachments,
                    },
                };
            },
        }),

        restoreFile: builder.mutation<
            ServerResponse<RestoreFileResponse>,
            { ids: (string | number)[] }
        >({
            query: ({ ids }) => {
                return {
                    url: `media-library/restore`,
                    method: "POST",
                    body: {
                        ids,
                    },
                };
            },
        }),

        deleteFile: builder.mutation<
            ServerResponse<DeleteFileResponse>,
            { ids: (string | number)[] }
        >({
            query: ({ ids }) => {
                return {
                    url: `media-library/delete`,
                    method: "DELETE",
                    body: {
                        ids,
                    },
                };
            },
        }),

        /* <fs_premium_only> */
        downloadFolder: builder.mutation<
            ServerResponse<DownloadFolderResponse>,
            { ids: (string | number)[] }
        >({
            query: ({ ids }) => {
                return {
                    url: `media-library/folder/download`,
                    method: "GET",
                    params: {
                        ids,
                    },
                };
            },
        }),

        trashFile: builder.mutation<
            ServerResponse<TrashFileResponse>,
            { ids: (string | number)[] }
        >({
            query: ({ ids }) => {
                return {
                    url: `media-library/trash`,
                    method: "POST",
                    body: {
                        ids,
                    },
                };
            },
        }),

        replaceMedia: builder.mutation<
            ReplaceMediaResponse,
            { id: number; formData: FormData }
        >({
            query: ({ id, formData }) => ({
                url: `replace-media/${id}`,
                method: "POST",
                body: formData,
                formData: true,
            }),
        }),

        toggleFavorite: builder.mutation<
            ServerResponse<{
                ids: number[];
                favorite: boolean;
                favorites: number;
            }>,
            { ids: (string | number)[]; favorite: boolean }
        >({
            query: ({ ids, favorite }) => ({
                url: `media-library/favorite`,
                method: "POST",
                body: { ids, favorite },
            }),
        }),

        duplicateMedia: builder.mutation<
            ServerResponse<any>,
            { ids: (string | number)[] }
        >({
            query: ({ ids }) => ({
                url: `media-library/files/duplicate`,
                method: "POST",
                body: { ids },
            }),
        }),
        /* </fs_premium_only> */
    }),
});

export const {
    useGetFoldersQuery,
    useLazyGetFolderQuery,
    useGetBreadcrumbsQuery,
    useCreateFolderMutation,
    useUpdateFolderMutation,
    useCopyFolderMutation,
    useMoveFolderMutation,
    useAssignFileMutation,
    useDeleteFolderMutation,
    useRestoreFileMutation,
    useDeleteFileMutation,
    /* <fs_premium_only> */
    useDownloadFolderMutation,
    useReplaceMediaMutation,
    useTrashFileMutation,
    useToggleFavoriteMutation,
    useDuplicateMediaMutation,
    /* </fs_premium_only> */
} = media;
