import { useCustomAlert } from "~/components/alert/Alert";
import { useAppDispatch } from "~/redux/hooks";
import { store } from "~/redux/store";
import useMedia from "./useMedia";
import {
    useAssignFileMutation,
    useDeleteFileMutation,
    useMoveFolderMutation,
    useRestoreFileMutation,
    /* <fs_premium_only> */
    useUpdateFolderMutation,
    useDownloadFolderMutation,
    useTrashFileMutation,
    useToggleFavoriteMutation,
    useDuplicateMediaMutation,
    /* </fs_premium_only> */
} from "~/redux/api/media";
import {
    removeFolder,
    setFolders,
    updateFolder,
} from "~/redux/features/media/media";
/* <fs_premium_only> */
import {
    useApplyWatermarkMutation,
    useRestoreOriginalsMutation,
} from "~/redux/api/watermark__premium_only";
/* </fs_premium_only> */

const useMediaActions = () => {
    const { setMedia, menu, folders, cutFolders } = useMedia();
    const [moveFolderMutation] = useMoveFolderMutation();
    const [assignFileMutation] = useAssignFileMutation();
    const [restoreFileMutation] = useRestoreFileMutation();
    const [deleteFileMutation] = useDeleteFileMutation();

    /* <fs_premium_only> */
    const [updateFolderMutation] = useUpdateFolderMutation();
    const [downloadFolderMutation] = useDownloadFolderMutation();
    const [restoreOriginalsMutation] = useRestoreOriginalsMutation();
    const [trashFileMutation] = useTrashFileMutation();
    const [toggleFavoriteMutation] = useToggleFavoriteMutation();
    const [applyWatermarkMutation] = useApplyWatermarkMutation();
    const [duplicateMediaMutation] = useDuplicateMediaMutation();
    /* </fs_premium_only> */

    const dispatch = useAppDispatch();

    const { showAlert } = useCustomAlert();

    const forceDisableBulkSelect = () => {
        const $ = (window as any).jQuery as any;

        const button = $(".select-mode-toggle-button");

        if (
            button.length &&
            (button.text().trim() === "Cancel" || button.hasClass("active"))
        ) {
            button[0].click();
        }

        if (window.wp?.media?.frame) {
            const selection = window.wp.media.frame.state().get("selection");
            selection?.reset();
        }
    };

    const moveFolder = async ({
        target,
        drop,
        dragged,
        folderId,
    }: {
        target: string | number;
        drop?: boolean;
        dragged?: string | number;
        folderId?: string | number;
    }) => {
        const ids = drop
            ? [dragged as string | number]
            : cutFolders?.folders?.map((folder) => folder.id) ?? [];

        const foldersToMove = drop
            ? Object.values(folders)
                  .flat()
                  .filter((f) => String(f.id) === String(dragged))
            : cutFolders?.folders ?? [];

        const finalId = target === "root" ? "root" : target;

        try {
            const response = await moveFolderMutation({
                id: finalId,
                ids,
            }).unwrap();

            dispatch(removeFolder(ids));

            const currentChildren =
                store.getState().media.folders[finalId] ?? [];

            let updatedChildren = currentChildren;

            if (drop && folderId && finalId === "root") {
                const targetIndex = currentChildren.findIndex(
                    (f) => String(f.id) === String(folderId),
                );

                if (targetIndex === -1) {
                    updatedChildren = [...currentChildren, ...foldersToMove];
                } else {
                    updatedChildren = [
                        ...currentChildren.slice(0, targetIndex),
                        ...foldersToMove,
                        ...currentChildren.slice(targetIndex),
                    ];
                }
            } else {
                updatedChildren = [...foldersToMove, ...currentChildren];
            }

            dispatch(
                setFolders({
                    id: finalId,
                    children: updatedChildren,
                }),
            );

            setMedia("moveFolder", { move: false, id: null });
            setMedia("cutFolders", { cut: false, folders: [] });

            showAlert({
                toast: true,
                type: "success",
                text:
                    response?.message ||
                    (drop
                        ? "Folder moved successfully"
                        : `${
                              ids.length > 1
                                  ? `${ids.length} folders`
                                  : "1 folder"
                          } cut successfully`),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        } catch (error: any) {
            setMedia("moveFolder", { move: false, id: null });

            showAlert({
                toast: true,
                type: "error",
                text:
                    error?.data?.message ||
                    (drop ? "Failed to move folder" : "Failed to cut folder"),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        }
    };

    const assignFile = async (
        id: string | number,
        attachments: (number | string)[],
    ) => {
        try {
            const response = await assignFileMutation({
                id,
                attachments,
            }).unwrap();

            forceDisableBulkSelect();

            dispatch(
                updateFolder({
                    id: id,
                    data: {
                        attachmentCount: Number(response?.data?.total) ?? 0,
                    },
                }),
            );

            dispatch(
                updateFolder({
                    id: response?.data?.previousFolder?.id!,
                    data: {
                        attachmentCount:
                            Number(response?.data?.previousFolder?.remaining) ??
                            0,
                    },
                }),
            );

            setMedia("uncategorized", response?.data?.uncategorizedCount ?? 0);

            if (
                menu !== "all" &&
                (response?.data?.previousFolder?.id || menu === "uncategorized")
            ) {
                response?.data?.assigned?.forEach(
                    (attachmentId: number | string) => {
                        const el = document.querySelector(
                            `.attachments-wrapper .attachment[data-id="${attachmentId}"]`,
                        ) as HTMLElement | null;

                        if (el) el.remove();
                    },
                );
            }

            showAlert({
                toast: true,
                type: "success",
                text:
                    response?.message ||
                    `${
                        attachments.length > 1
                            ? `${attachments.length} files`
                            : "1 file"
                    } assigned successfully`,
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        } catch (error: any) {
            showAlert({
                toast: true,
                type: "error",
                text: error?.data?.message || "Failed to assign files",
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        }
    };

    const openMediaEdit = (id: number) => {
        const currentUrl = new URL(window.location.href);

        currentUrl.searchParams.set("item", String(id));

        window.history.pushState({}, "", currentUrl.toString());

        window.dispatchEvent(new PopStateEvent("popstate"));
    };

    const getFileLink = (attachment: any) => {
        const url = attachment?.url;
        if (!url) return;
        navigator.clipboard.writeText(url);

        showAlert({
            toast: true,
            type: "success",
            text: "File URL copied to clipboard",
            timer: 3000,
            timerProgressBar: true,
            showConfirmButton: false,
        });
    };

    const restoreFile = async (ids: (string | number)[]) => {
        showAlert({
            type: "info",
            title: "Confirm Restore",
            text: `Are you sure you want to restore ${
                ids.length > 1 ? "these files" : "this file"
            } from trash?`,
            showCancelButton: true,
            confirmButtonText: "Restore",
            onConfirm: async () => {
                try {
                    const response = await restoreFileMutation({
                        ids,
                    }).unwrap();

                    forceDisableBulkSelect();

                    if (response?.data?.restored?.length) {
                        response.data.restored.forEach((attachmentId) => {
                            const el = document.querySelector(
                                `.attachments-wrapper .attachment[data-id="${attachmentId}"]`,
                            ) as HTMLElement | null;

                            if (el) el.remove();
                        });
                    }

                    response?.data?.folders?.forEach((folder) => {
                        dispatch(
                            updateFolder({
                                id: folder?.id,
                                data: {
                                    attachmentCount:
                                        Number(folder?.remaining) ?? 0,
                                },
                            }),
                        );
                    });

                    setMedia("allFiles", response?.data?.allFiles ?? 0);
                    setMedia(
                        "uncategorized",
                        response?.data?.uncategorized ?? 0,
                    );
                    setMedia("trash", response?.data?.trash ?? 0);

                    showAlert({
                        toast: true,
                        type: "success",
                        text:
                            response?.message ||
                            `${ids.length} file(s) restored successfully`,
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                } catch (error: any) {
                    showAlert({
                        toast: true,
                        type: "error",
                        text: error?.data?.message || "Failed to restore files",
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                }
            },
        });
    };

    const deleteFile = async (ids: (string | number)[]) => {
        showAlert({
            type: "error",
            title: "Confirm Delete",
            text: `Are you sure you want to delete ${
                ids.length > 1 ? "these files" : "this file"
            } permanently?`,
            showCancelButton: true,
            confirmButtonText: "Delete",
            onConfirm: async () => {
                try {
                    const response = await deleteFileMutation({ ids }).unwrap();

                    forceDisableBulkSelect();

                    if (response?.data?.deleted?.length) {
                        response.data.deleted.forEach((attachmentId) => {
                            const el = document.querySelector(
                                `.attachments-wrapper .attachment[data-id="${attachmentId}"]`,
                            ) as HTMLElement | null;

                            if (el) el.remove();
                        });
                    }

                    response?.data?.folders?.forEach((folder) => {
                        dispatch(
                            updateFolder({
                                id: folder?.id,
                                data: {
                                    attachmentCount:
                                        Number(folder?.remaining) ?? 0,
                                },
                            }),
                        );
                    });

                    setMedia("allFiles", response?.data?.allFiles ?? 0);
                    setMedia(
                        "uncategorized",
                        response?.data?.uncategorized ?? 0,
                    );
                    setMedia("trash", response?.data?.trash ?? 0);

                    showAlert({
                        toast: true,
                        type: "success",
                        text:
                            response?.message ||
                            `${ids.length} file(s) deleted successfully`,
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                } catch (error: any) {
                    showAlert({
                        toast: true,
                        type: "error",
                        text: error?.data?.message || "Failed to delete files",
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                }
            },
        });
    };

    /* <fs_premium_only> */
    const colorUpdate = async (id: string | number, color: string | null) => {
        try {
            await updateFolderMutation({ id, color }).unwrap();
        } catch (error: any) {
            showAlert({
                toast: true,
                type: "error",
                text: error?.data?.message || "Failed to update folder color",
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        }
    };

    const downloadFolder = async (ids: (string | number)[]) => {
        try {
            const response = await downloadFolderMutation({ ids }).unwrap();

            const downloadUrl = response?.data?.url;
            if (downloadUrl) {
                const link = document.createElement("a");
                link.href = downloadUrl;
                link.download = "";
                document.body.appendChild(link);
                link.click();
                document.body.removeChild(link);
            }
        } catch (error: any) {
            showAlert({
                toast: true,
                type: "error",
                text: error?.data?.message || "Failed to download folder",
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        }
    };

    const fileDownload = (attachment: any) => {
        const url = attachment?.url;
        if (!url) return;

        const link = document.createElement("a");
        link.href = url;
        link.download = "";
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const bustAttachmentImageCache = (
        successIds: (string | number)[],
        isWatermarked: boolean,
    ) => {
        const v = Date.now();
        successIds.forEach((id) => {
            const thumb = document.querySelector(
                `.attachments-wrapper .attachment[data-id="${id}"] .thumbnail img`,
            ) as HTMLImageElement | null;
            if (thumb) {
                const base = thumb.src.split("?")[0];
                thumb.src = `${base}?v=${v}`;
            }

            const wpAtt = (window as any).wp?.media?.attachment(id);
            if (wpAtt) {
                const currentUrl = wpAtt.get("url") as string | undefined;
                if (currentUrl) {
                    wpAtt.set("url", `${currentUrl.split("?")[0]}?v=${v}`);
                }

                const sizes = wpAtt.get("sizes") as
                    | Record<string, { url: string }>
                    | undefined;
                if (sizes) {
                    const bustedSizes = Object.fromEntries(
                        Object.entries(sizes).map(([key, size]) => [
                            key,
                            {
                                ...size,
                                url: `${size.url.split("?")[0]}?v=${v}`,
                            },
                        ]),
                    );
                    wpAtt.set("sizes", bustedSizes);
                }

                wpAtt.set("isWatermarked", isWatermarked);
            }
        });
    };

    const applyWatermark = async (ids: (string | number)[]) => {
        showAlert({
            type: "info",
            title: "Apply Watermark",
            text: `Are you sure you want to apply watermark to ${
                ids.length > 1 ? "these files" : "this file"
            }?`,
            showCancelButton: true,
            confirmButtonText: "Apply",
            onConfirm: async () => {
                try {
                    const response = await applyWatermarkMutation({
                        ids: ids as number[],
                    }).unwrap();

                    const successIds = (response?.data?.results ?? [])
                        .filter((r) => r.success)
                        .map((r) => r.id);
                    bustAttachmentImageCache(successIds, true);

                    forceDisableBulkSelect();

                    showAlert({
                        toast: true,
                        type: "success",
                        text:
                            response?.message ||
                            `${ids.length} file(s) watermark applied successfully`,
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                } catch (error: any) {
                    showAlert({
                        toast: true,
                        type: "error",
                        text:
                            error?.data?.message || "Failed to apply watermark",
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                }
            },
        });
    };

    const removeWatermark = async (ids: (string | number)[]) => {
        showAlert({
            type: "error",
            title: "Remove Watermark",
            text: `Are you sure you want to remove watermark from ${
                ids.length > 1 ? "these files" : "this file"
            }?`,
            showCancelButton: true,
            confirmButtonText: "Remove",
            onConfirm: async () => {
                try {
                    const response = await restoreOriginalsMutation({
                        ids: ids as number[],
                    }).unwrap();

                    const successIds = (response?.data?.results ?? [])
                        .filter((r) => r.success)
                        .map((r) => r.id);
                    bustAttachmentImageCache(successIds, false);

                    forceDisableBulkSelect();

                    showAlert({
                        toast: true,
                        type: "success",
                        text:
                            response?.message ||
                            `${ids.length} file(s) watermark removed successfully`,
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                } catch (error: any) {
                    showAlert({
                        toast: true,
                        type: "error",
                        text:
                            error?.data?.message ||
                            "Failed to remove watermark",
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                }
            },
        });
    };

    const trashFile = async (ids: (string | number)[]) => {
        showAlert({
            type: "error",
            title: "Confirm Trash",
            text: `Are you sure you want to move ${
                ids.length > 1 ? "these files" : "this file"
            } to trash?`,
            showCancelButton: true,
            confirmButtonText: "Trash",
            onConfirm: async () => {
                try {
                    const response = await trashFileMutation({ ids }).unwrap();

                    if (response?.data?.trashed?.length) {
                        response.data.trashed.forEach((attachmentId) => {
                            const el = document.querySelector(
                                `.attachments-wrapper .attachment[data-id="${attachmentId}"]`,
                            ) as HTMLElement | null;

                            if (el) el.remove();
                        });
                    }

                    forceDisableBulkSelect();

                    response?.data?.folders?.forEach((folder) => {
                        dispatch(
                            updateFolder({
                                id: folder?.id,
                                data: {
                                    attachmentCount:
                                        Number(folder?.remaining) ?? 0,
                                },
                            }),
                        );
                    });

                    setMedia("allFiles", response?.data?.allFiles ?? 0);
                    setMedia(
                        "uncategorized",
                        response?.data?.uncategorized ?? 0,
                    );
                    setMedia("trash", response?.data?.trash ?? 0);

                    showAlert({
                        toast: true,
                        type: "success",
                        text:
                            response?.message ||
                            `${ids.length} file(s) moved to trash successfully`,
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                } catch (error: any) {
                    showAlert({
                        toast: true,
                        type: "error",
                        text: error?.data?.message || "Failed to trash files",
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                }
            },
        });
    };

    const toggleFavorite = async (
        ids: (string | number)[],
        favorite: boolean,
    ) => {
        try {
            const response = await toggleFavoriteMutation({
                ids,
                favorite,
            }).unwrap();

            setMedia("favorites", response?.data?.favorites ?? 0);

            ids.forEach((id) => {
                const wpAtt = (window as any).wp?.media?.attachment(id);
                if (wpAtt) {
                    wpAtt.set("isFavorite", favorite);
                }
            });

            showAlert({
                toast: true,
                type: "success",
                text:
                    response?.message ||
                    (favorite
                        ? `${
                              ids.length > 1 ? `${ids.length} files` : "1 file"
                          } added to favorites`
                        : `${
                              ids.length > 1 ? `${ids.length} files` : "1 file"
                          } removed from favorites`),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        } catch (error: any) {
            showAlert({
                toast: true,
                type: "error",
                text: error?.data?.message || "Failed to update favorites",
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        }
    };

    const duplicateMedia = async (ids: (string | number)[]) => {
        showAlert({
            type: "info",
            title: "Confirm Duplicate",
            text: `Are you sure you want to duplicate ${
                ids.length > 1 ? "these files" : "this file"
            }?`,
            showCancelButton: true,
            confirmButtonText: "Duplicate",
            onConfirm: async () => {
                try {
                    const response = await duplicateMediaMutation({
                        ids,
                    }).unwrap();

                    showAlert({
                        toast: true,
                        type: "success",
                        text:
                            response?.message ||
                            `${ids.length} file(s) duplicated successfully`,
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                } catch (error: any) {
                    showAlert({
                        toast: true,
                        type: "error",
                        text:
                            error?.data?.message || "Failed to duplicate files",
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                }
            },
        });
    };
    /* </fs_premium_only> */

    return {
        moveFolder,
        assignFile,
        openMediaEdit,
        getFileLink,
        restoreFile,
        deleteFile,
        /* <fs_premium_only> */
        colorUpdate,
        downloadFolder,
        fileDownload,
        toggleFavorite,
        trashFile,
        applyWatermark,
        removeWatermark,
        duplicateMedia,
        /* </fs_premium_only> */
    };
};

export default useMediaActions;
