import { Attachment, MediaContextMenu } from "~/types/media/media";
import useMediaActions from "./useMediaActions";
/* <fs_premium_only> */
import { useReplaceMedia } from "~/shared/hooks/useReplaceMedia__premium_only";
/* </fs_premium_only> */

type HandleFileContextParams = {
    key: MediaContextMenu;
    attachments: Attachment[];
};

const useFileContext = () => {
    const {
        getFileLink,
        openMediaEdit,
        restoreFile,
        deleteFile,
        /* <fs_premium_only> */
        fileDownload,
        toggleFavorite,
        applyWatermark,
        removeWatermark,
        trashFile,
        duplicateMedia,
        /* </fs_premium_only> */
    } = useMediaActions();

    /* <fs_premium_only> */
    const { replaceAttachment } = useReplaceMedia();
    /* </fs_premium_only> */

    const handleFileContext = ({
        key,
        attachments,
    }: HandleFileContextParams) => {
        const ids = attachments?.map((attachment) => attachment?.id) ?? [];

        switch (key) {
            case "open":
                return;
            case "view":
                return;
            case "get":
                getFileLink(attachments[0]);
                return;
            case "edit":
                openMediaEdit(ids?.[0]);
                return;
            case "download":
                /* <fs_premium_only> */
                if (!pnpnm?.isPro) return;

                fileDownload(ids?.[0]);
                /* </fs_premium_only> */
                return;
            case "duplicate":
                /* <fs_premium_only> */
                if (!pnpnm?.isPro) return;

                duplicateMedia(ids);
                /* </fs_premium_only> */
                return;
            case "replace":
                /* <fs_premium_only> */
                if (!pnpnm?.isPro) return;

                replaceAttachment(ids?.[0]);
                /* </fs_premium_only> */
                return;
            case "favorite":
                /* <fs_premium_only> */
                if (!pnpnm?.isPro) return;

                toggleFavorite(ids, true);
                /* </fs_premium_only> */
                return;
            case "unfavorite":
                /* <fs_premium_only> */
                if (!pnpnm?.isPro) return;

                toggleFavorite(ids, false);
                /* </fs_premium_only> */
                return;
            case "apply":
                /* <fs_premium_only> */
                if (!pnpnm?.isPro) return;

                applyWatermark(ids);
                /* </fs_premium_only> */
                return;
            case "remove":
                /* <fs_premium_only> */
                if (!pnpnm?.isPro) return;

                removeWatermark(ids);
                /* </fs_premium_only> */
                return;
            case "trash":
                /* <fs_premium_only> */
                if (!pnpnm?.isPro) return;

                trashFile(ids);
                /* </fs_premium_only> */
                return;
            case "restore":
                restoreFile(ids);
                return;
            case "delete":
                deleteFile(ids);
                return;
            default: {
                const exhaustiveCheck: never = key;
                return exhaustiveCheck;
            }
        }
    };

    return handleFileContext;
};

export default useFileContext;
